A simple array-based particle object pool:

```cpp
#include <vector>

struct FProjectile {
    bool IsActive = false;
    float Position = 0.0f;
};

class UProjectilePool {
private:
    std::vector<FProjectile> Pool;

public:
    UProjectilePool(int Size) {
        Pool.resize(Size);
    }

    FProjectile* Spawn() {
        for (auto& Item : Pool) {
            if (!Item.IsActive) {
                Item.IsActive = true;
                Item.Position = 0.0f;
                return &Item; // Reuses index instead of dynamic allocation!
            }
        }
        return nullptr; // Pool fully exhausted
    }
};
```
